import { useState, useEffect, useRef } from "react";

const LOGO_SRC = "data:image/jpeg;base64,";

/* ─── CSS ────────────────────────────────────────────────────── */
const css = `
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --brand:    #C96A3A;
    --brand-dk: #A8542C;
    --text-dk:  #4A2D1F;
    --text-md:  #8A6A55;
    --text-lt:  #B09080;
    --bg:       #FFF8EF;
    --bg-card:  #FFFFFF;
    --bg-soft:  #F4E2CC;
    --bg-warm:  #FDF0E0;
    --trust:    #5C8A63;
    --trust-bg: #EAF3EB;
    --border:   rgba(201,106,58,0.12);
    --shadow:   0 2px 16px rgba(74,45,31,0.07);
    --shadow-md:0 6px 32px rgba(74,45,31,0.10);
    --r:        12px;
    --r-lg:     20px;
    --font: -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", "Noto Sans SC", sans-serif;
    --max: 1180px;
    --transition: 0.22s cubic-bezier(.4,0,.2,1);
  }

  html { scroll-behavior: smooth; }

  body {
    font-family: var(--font);
    background: var(--bg);
    color: var(--text-dk);
    -webkit-font-smoothing: antialiased;
    line-height: 1.6;
  }

  /* ── HEADER ── */
  .header {
    position: sticky; top: 0; z-index: 200;
    background: rgba(255,248,239,0.92);
    backdrop-filter: blur(14px);
    border-bottom: 1px solid var(--border);
    transition: box-shadow var(--transition);
  }
  .header.scrolled { box-shadow: 0 2px 24px rgba(74,45,31,0.08); }
  .header-inner {
    max-width: var(--max); margin: 0 auto;
    display: flex; align-items: center;
    justify-content: space-between;
    padding: 0 32px; height: 64px;
  }
  .logo-group { display: flex; align-items: center; gap: 10px; cursor: pointer; }
  .logo-img-wrap {
    width: 38px; height: 38px; border-radius: 50%;
    overflow: hidden; flex-shrink: 0;
    background: var(--bg-soft);
    display: flex; align-items: center; justify-content: center;
  }
  .logo-img-wrap img { width: 100%; height: 100%; object-fit: cover; }
  .logo-name {
    font-size: 17px; font-weight: 700; letter-spacing: .02em;
    color: var(--text-dk);
  }
  .logo-tag {
    font-size: 11px; font-weight: 600; color: var(--brand);
    background: rgba(201,106,58,0.10);
    padding: 2px 8px; border-radius: 20px; white-space: nowrap;
  }
  .nav-links { display: flex; gap: 28px; list-style: none; }
  .nav-links a {
    font-size: 13.5px; color: var(--text-md); text-decoration: none;
    font-weight: 500; transition: color var(--transition);
    white-space: nowrap;
  }
  .nav-links a:hover { color: var(--brand); }
  .btn-contact {
    font-size: 13px; font-weight: 600;
    color: var(--brand); border: 1.5px solid var(--brand);
    background: transparent; border-radius: 50px;
    padding: 7px 20px; cursor: pointer;
    font-family: var(--font);
    transition: background var(--transition), color var(--transition), transform var(--transition);
    white-space: nowrap;
  }
  .btn-contact:hover { background: var(--brand); color: #fff; transform: translateY(-1px); }
  .hamburger {
    display: none; background: none; border: none;
    cursor: pointer; padding: 6px; color: var(--text-dk);
  }
  .mobile-nav {
    display: none; background: var(--bg-card);
    border-top: 1px solid var(--border);
    padding: 16px 24px;
    flex-direction: column; gap: 0;
  }
  .mobile-nav a {
    display: block; padding: 12px 0;
    font-size: 15px; color: var(--text-dk); text-decoration: none;
    border-bottom: 1px solid var(--border); font-weight: 500;
  }
  .mobile-nav a:last-child { border-bottom: none; }

  /* ── HERO ── */
  .hero {
    max-width: var(--max); margin: 0 auto;
    display: grid; grid-template-columns: 1fr 1fr;
    align-items: center; gap: 64px;
    padding: 88px 32px 80px;
  }
  .hero-tag {
    display: inline-flex; align-items: center; gap: 6px;
    font-size: 12px; font-weight: 600;
    color: var(--brand); letter-spacing: .08em;
    text-transform: uppercase;
    background: rgba(201,106,58,0.09);
    border: 1px solid rgba(201,106,58,0.18);
    padding: 5px 14px; border-radius: 50px;
    margin-bottom: 24px;
  }
  .hero-title {
    font-size: clamp(30px, 4vw, 46px);
    font-weight: 800; line-height: 1.22;
    color: var(--text-dk); margin-bottom: 20px;
    letter-spacing: -.01em;
  }
  .hero-title span { color: var(--brand); }
  .hero-desc {
    font-size: 15.5px; color: var(--text-md);
    line-height: 1.85; margin-bottom: 36px; max-width: 440px;
  }
  .hero-actions { display: flex; gap: 14px; flex-wrap: wrap; margin-bottom: 40px; }
  .btn-primary {
    font-size: 14.5px; font-weight: 700;
    background: var(--brand); color: #fff;
    border: none; border-radius: 50px;
    padding: 13px 28px; cursor: pointer;
    font-family: var(--font);
    box-shadow: 0 4px 18px rgba(201,106,58,0.32);
    transition: background var(--transition), transform var(--transition), box-shadow var(--transition);
  }
  .btn-primary:hover { background: var(--brand-dk); transform: translateY(-2px); box-shadow: 0 8px 28px rgba(201,106,58,0.38); }
  .btn-ghost {
    font-size: 14px; font-weight: 600;
    color: var(--text-dk); background: transparent;
    border: 1.5px solid rgba(74,45,31,0.18);
    border-radius: 50px; padding: 12px 24px; cursor: pointer;
    font-family: var(--font);
    transition: border-color var(--transition), color var(--transition), transform var(--transition);
  }
  .btn-ghost:hover { border-color: var(--brand); color: var(--brand); transform: translateY(-2px); }
  .hero-trust { display: flex; gap: 20px; flex-wrap: wrap; }
  .trust-item {
    display: flex; align-items: center; gap: 7px;
    font-size: 13px; font-weight: 500; color: var(--text-md);
  }
  .trust-dot {
    width: 6px; height: 6px; border-radius: 50%;
    background: var(--trust); flex-shrink: 0;
  }
  /* Hero Visual */
  .hero-visual {
    display: flex; justify-content: flex-end; align-items: center;
  }
  .hero-illus {
    width: 100%; max-width: 420px;
    background: var(--bg-warm);
    border: 1.5px solid var(--border);
    border-radius: var(--r-lg);
    overflow: hidden; position: relative;
  }
  .hero-illus-inner {
    padding: 40px; display: flex; justify-content: center; align-items: center;
    min-height: 340px;
  }

  /* ── SECTION COMMON ── */
  .section { padding: 80px 32px; }
  .section-inner { max-width: var(--max); margin: 0 auto; }
  .section-label {
    font-size: 11.5px; font-weight: 700; letter-spacing: .1em;
    text-transform: uppercase; color: var(--brand); margin-bottom: 12px;
  }
  .section-title {
    font-size: clamp(22px, 3vw, 32px); font-weight: 800;
    color: var(--text-dk); line-height: 1.25; margin-bottom: 14px;
  }
  .section-desc {
    font-size: 15px; color: var(--text-md);
    line-height: 1.85; max-width: 600px; margin-bottom: 48px;
  }

  /* ── BRAND EXPLAIN ── */
  .brand-section { background: var(--bg-card); }
  .brand-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 64px; align-items: start; }
  .brand-text p { font-size: 15px; color: var(--text-md); line-height: 1.9; margin-bottom: 16px; }
  .brand-cards { display: flex; flex-direction: column; gap: 16px; }
  .brand-card {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: var(--r);
    padding: 24px;
    display: flex; gap: 18px; align-items: flex-start;
    transition: box-shadow var(--transition), transform var(--transition);
  }
  .brand-card:hover { box-shadow: var(--shadow-md); transform: translateY(-2px); }
  .brand-card-icon {
    width: 44px; height: 44px; flex-shrink: 0;
    background: rgba(201,106,58,0.10); border-radius: 10px;
    display: flex; align-items: center; justify-content: center;
  }
  .brand-card-body h4 { font-size: 15px; font-weight: 700; color: var(--text-dk); margin-bottom: 5px; }
  .brand-card-body p { font-size: 13.5px; color: var(--text-md); line-height: 1.7; }

  /* ── MISSION ── */
  .mission-section { background: var(--bg); }
  .mission-box {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: var(--r-lg);
    padding: 40px;
    box-shadow: var(--shadow);
  }
  .mission-header { display: flex; justify-content: space-between; align-items: flex-start; gap: 24px; margin-bottom: 32px; flex-wrap: wrap; }
  .mission-name { font-size: 13px; font-weight: 600; color: var(--text-md); margin-bottom: 6px; }
  .mission-title { font-size: 20px; font-weight: 700; color: var(--text-dk); margin-bottom: 10px; }
  .mission-desc { font-size: 14px; color: var(--text-md); line-height: 1.7; max-width: 480px; }
  .mission-btn {
    font-size: 13.5px; font-weight: 600;
    color: var(--brand); border: 1.5px solid var(--brand);
    background: transparent; border-radius: 50px;
    padding: 10px 22px; cursor: pointer; font-family: var(--font);
    white-space: nowrap; align-self: flex-start;
    transition: background var(--transition), color var(--transition);
  }
  .mission-btn:hover { background: var(--brand); color: #fff; }
  .progress-label { display: flex; justify-content: space-between; margin-bottom: 10px; }
  .progress-label span { font-size: 13px; color: var(--text-md); }
  .progress-label strong { font-size: 13px; font-weight: 700; color: var(--brand); }
  .progress-track {
    height: 8px; background: var(--bg-soft); border-radius: 50px; overflow: hidden; margin-bottom: 24px;
  }
  .progress-fill {
    height: 100%; border-radius: 50px;
    background: linear-gradient(90deg, var(--brand), #E8894A);
    width: 0; transition: width 1.4s cubic-bezier(.4,0,.2,1);
  }
  .mission-stats { display: grid; grid-template-columns: repeat(4, 1fr); gap: 20px; }
  .stat-item { text-align: center; padding: 16px; background: var(--bg); border-radius: var(--r); }
  .stat-num { font-size: 24px; font-weight: 800; color: var(--brand); margin-bottom: 4px; }
  .stat-lbl { font-size: 12px; color: var(--text-lt); }

  /* ── FLOW ── */
  .flow-section { background: var(--bg-card); }
  .flow-steps {
    display: grid; grid-template-columns: repeat(5, 1fr);
    gap: 0; position: relative;
  }
  .flow-step { display: flex; flex-direction: column; align-items: center; text-align: center; position: relative; padding: 0 8px; }
  .flow-step:not(:last-child)::after {
    content: '';
    position: absolute; top: 28px; left: calc(50% + 28px);
    width: calc(100% - 56px); height: 1.5px;
    background: var(--bg-soft);
  }
  .flow-num {
    width: 56px; height: 56px; border-radius: 50%;
    background: var(--bg); border: 2px solid var(--border);
    display: flex; align-items: center; justify-content: center;
    margin-bottom: 18px; position: relative; z-index: 1;
    transition: border-color var(--transition), background var(--transition);
  }
  .flow-step:hover .flow-num { border-color: var(--brand); background: rgba(201,106,58,0.06); }
  .flow-n { font-size: 18px; font-weight: 800; color: var(--brand); }
  .flow-step h4 { font-size: 14px; font-weight: 700; color: var(--text-dk); margin-bottom: 8px; }
  .flow-step p { font-size: 12.5px; color: var(--text-md); line-height: 1.65; }

  /* ── TICKETS ── */
  .ticket-section { background: var(--bg); }
  .ticket-notice {
    font-size: 13px; color: var(--text-md);
    background: var(--bg-warm); border: 1px solid var(--border);
    border-radius: var(--r); padding: 14px 20px;
    margin-bottom: 32px; display: flex; align-items: center; gap: 10px;
  }
  .ticket-grid { display: grid; grid-template-columns: repeat(5, 1fr); gap: 16px; }
  .ticket-card {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: var(--r);
    padding: 24px 20px;
    display: flex; flex-direction: column; gap: 6px;
    transition: box-shadow var(--transition), transform var(--transition), border-color var(--transition);
    position: relative; overflow: hidden;
  }
  .ticket-card:hover { box-shadow: var(--shadow-md); transform: translateY(-3px); border-color: rgba(201,106,58,0.3); }
  .ticket-card.featured { border-color: var(--brand); }
  .ticket-tag {
    position: absolute; top: 0; right: 0;
    font-size: 10px; font-weight: 700;
    background: var(--brand); color: #fff;
    padding: 4px 10px; border-radius: 0 var(--r) 0 var(--r);
  }
  .ticket-name { font-size: 14px; font-weight: 700; color: var(--text-dk); }
  .ticket-price { font-size: 22px; font-weight: 800; color: var(--brand); margin: 4px 0; }
  .ticket-price sub { font-size: 12px; font-weight: 500; color: var(--text-md); }
  .ticket-desc { font-size: 12px; color: var(--text-md); line-height: 1.6; }
  .ticket-upcoming {
    display: block; text-align: center;
    font-size: 11px; color: var(--text-lt); margin-top: 10px;
  }
  .btn-upcoming {
    display: block; width: 100%; margin-top: 12px;
    font-size: 12px; font-weight: 600;
    color: var(--text-lt); background: var(--bg);
    border: 1px dashed rgba(74,45,31,0.15);
    border-radius: 50px; padding: 8px; cursor: default;
    font-family: var(--font); text-align: center;
  }

  /* ── SHELTERS ── */
  .shelter-section { background: var(--bg-card); }
  .shelter-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 24px; }
  .shelter-card {
    border: 1px solid var(--border);
    border-radius: var(--r-lg);
    overflow: hidden; background: var(--bg-card);
    transition: box-shadow var(--transition), transform var(--transition);
  }
  .shelter-card:hover { box-shadow: var(--shadow-md); transform: translateY(-3px); }
  .shelter-photo {
    height: 160px; background: var(--bg-warm);
    display: flex; align-items: center; justify-content: center;
    position: relative; overflow: hidden;
  }
  .shelter-photo-placeholder {
    width: 100%; height: 100%;
    display: flex; align-items: center; justify-content: center;
  }
  /* Replace these with real <img> tags */
  .shelter-photo-label {
    position: absolute; bottom: 10px; left: 12px;
    font-size: 10px; font-weight: 600; color: var(--text-md);
    background: rgba(255,255,255,0.85); padding: 3px 9px; border-radius: 20px;
  }
  .shelter-body { padding: 22px; }
  .shelter-status {
    display: inline-block; font-size: 11px; font-weight: 700;
    padding: 3px 10px; border-radius: 20px; margin-bottom: 10px;
  }
  .status-active { background: var(--trust-bg); color: var(--trust); }
  .status-wait { background: #FFF3E0; color: #C96A3A; }
  .shelter-name { font-size: 15px; font-weight: 700; color: var(--text-dk); margin-bottom: 12px; }
  .shelter-meta { display: flex; flex-direction: column; gap: 7px; margin-bottom: 18px; }
  .shelter-meta-row { display: flex; gap: 8px; align-items: flex-start; font-size: 13px; color: var(--text-md); }
  .shelter-meta-label { color: var(--text-lt); flex-shrink: 0; font-size: 12px; }
  .btn-detail {
    width: 100%; font-size: 13px; font-weight: 600;
    color: var(--brand); background: transparent;
    border: 1.5px solid rgba(201,106,58,0.25);
    border-radius: 50px; padding: 9px; cursor: pointer;
    font-family: var(--font);
    transition: border-color var(--transition), background var(--transition), color var(--transition);
  }
  .btn-detail:hover { border-color: var(--brand); background: rgba(201,106,58,0.05); }

  /* ── REPORT ── */
  .report-section { background: var(--bg); }
  .report-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: start; }
  .report-box {
    background: var(--bg-card); border: 1px solid var(--border);
    border-radius: var(--r-lg); padding: 32px; box-shadow: var(--shadow);
  }
  .report-tag {
    display: inline-block; font-size: 11px; font-weight: 700;
    background: var(--trust-bg); color: var(--trust);
    padding: 3px 12px; border-radius: 20px; margin-bottom: 18px;
    letter-spacing: .04em;
  }
  .report-list { list-style: none; margin-bottom: 24px; }
  .report-list li {
    display: flex; justify-content: space-between;
    padding: 11px 0; border-bottom: 1px solid var(--border);
    font-size: 14px;
  }
  .report-list li:last-child { border-bottom: none; }
  .report-list .rl { color: var(--text-lt); font-size: 13px; }
  .report-list .rv { font-weight: 600; color: var(--text-dk); }
  .report-entries { display: flex; flex-direction: column; gap: 14px; margin-bottom: 24px; }
  .report-entry {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: var(--r);
    padding: 18px 20px;
    display: flex; gap: 16px; align-items: center;
    cursor: pointer;
    transition: box-shadow var(--transition), transform var(--transition);
  }
  .report-entry:hover { box-shadow: var(--shadow-md); transform: translateX(4px); }
  .report-entry-icon {
    width: 40px; height: 40px; flex-shrink: 0;
    background: var(--bg-warm); border-radius: 10px;
    display: flex; align-items: center; justify-content: center;
  }
  .report-entry-body h4 { font-size: 14px; font-weight: 700; color: var(--text-dk); margin-bottom: 3px; }
  .report-entry-body p { font-size: 12px; color: var(--text-md); }

  /* ── WHY ── */
  .why-section { background: var(--bg-card); }
  .why-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 24px; }
  .why-card {
    padding: 32px;
    border: 1px solid var(--border);
    border-radius: var(--r-lg); background: var(--bg);
    transition: box-shadow var(--transition), transform var(--transition);
  }
  .why-card:hover { box-shadow: var(--shadow-md); transform: translateY(-3px); }
  .why-icon {
    width: 48px; height: 48px;
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 12px;
    display: flex; align-items: center; justify-content: center;
    margin-bottom: 20px;
  }
  .why-card h3 { font-size: 16px; font-weight: 700; color: var(--text-dk); margin-bottom: 10px; }
  .why-card p { font-size: 13.5px; color: var(--text-md); line-height: 1.75; }

  /* ── WECHAT ── */
  .wechat-section { background: var(--bg); }
  .wechat-box {
    max-width: 780px; margin: 0 auto;
    background: var(--bg-card); border: 1px solid var(--border);
    border-radius: var(--r-lg); padding: 48px;
    display: grid; grid-template-columns: 1fr auto;
    gap: 40px; align-items: center; box-shadow: var(--shadow);
  }
  .wechat-text h2 { font-size: 24px; font-weight: 800; color: var(--text-dk); margin-bottom: 14px; }
  .wechat-text p { font-size: 14.5px; color: var(--text-md); line-height: 1.8; margin-bottom: 28px; }
  .qr-placeholder {
    width: 120px; height: 120px; flex-shrink: 0;
    background: var(--bg-soft);
    border: 1.5px dashed rgba(201,106,58,0.3);
    border-radius: var(--r);
    display: flex; flex-direction: column;
    align-items: center; justify-content: center; gap: 8px;
  }
  .qr-placeholder span { font-size: 11px; color: var(--text-lt); text-align: center; font-weight: 500; }

  /* ── ENTERPRISE ── */
  .enterprise-section { background: #2C1A0F; }
  .enterprise-inner { max-width: var(--max); margin: 0 auto; padding: 80px 32px; }
  .enterprise-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 64px; align-items: center; }
  .enterprise-label { font-size: 11px; font-weight: 700; letter-spacing: .1em; text-transform: uppercase; color: #E8894A; margin-bottom: 14px; }
  .enterprise-title { font-size: 30px; font-weight: 800; color: #fff; line-height: 1.25; margin-bottom: 16px; }
  .enterprise-desc { font-size: 14.5px; color: rgba(255,255,255,0.65); line-height: 1.85; margin-bottom: 32px; }
  .enterprise-tags { display: flex; flex-wrap: wrap; gap: 10px; margin-bottom: 32px; }
  .enterprise-tag {
    font-size: 12.5px; font-weight: 500;
    color: rgba(255,255,255,0.75);
    border: 1px solid rgba(255,255,255,0.15);
    border-radius: 50px; padding: 6px 16px;
  }
  .btn-enterprise {
    font-size: 14px; font-weight: 700;
    background: #C96A3A; color: #fff; border: none;
    border-radius: 50px; padding: 13px 28px; cursor: pointer;
    font-family: var(--font);
    transition: background var(--transition), transform var(--transition);
  }
  .btn-enterprise:hover { background: #E8894A; transform: translateY(-2px); }
  .enterprise-visual {
    background: rgba(255,255,255,0.04);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: var(--r-lg); padding: 36px;
  }
  .enterprise-item {
    display: flex; align-items: center; gap: 14px;
    padding: 14px 0; border-bottom: 1px solid rgba(255,255,255,0.06);
  }
  .enterprise-item:last-child { border-bottom: none; }
  .ent-dot { width: 6px; height: 6px; border-radius: 50%; background: #C96A3A; flex-shrink: 0; }
  .enterprise-item span { font-size: 14px; color: rgba(255,255,255,0.7); }

  /* ── FAQ ── */
  .faq-section { background: var(--bg-card); }
  .faq-list { max-width: 720px; margin: 0 auto; }
  .faq-item {
    border-bottom: 1px solid var(--border); overflow: hidden;
  }
  .faq-q {
    width: 100%; display: flex; justify-content: space-between; align-items: center;
    padding: 20px 0; background: none; border: none; cursor: pointer;
    font-size: 15px; font-weight: 600; color: var(--text-dk);
    font-family: var(--font); text-align: left; gap: 16px;
  }
  .faq-q:hover { color: var(--brand); }
  .faq-chevron {
    flex-shrink: 0; transition: transform var(--transition); color: var(--text-lt);
  }
  .faq-chevron.open { transform: rotate(180deg); color: var(--brand); }
  .faq-a {
    max-height: 0; overflow: hidden;
    transition: max-height 0.35s cubic-bezier(.4,0,.2,1), padding 0.35s;
  }
  .faq-a.open { max-height: 200px; }
  .faq-a p { padding-bottom: 20px; font-size: 14px; color: var(--text-md); line-height: 1.8; }

  /* ── FOOTER ── */
  .footer { background: #1E0F05; padding: 56px 32px 32px; }
  .footer-inner { max-width: var(--max); margin: 0 auto; }
  .footer-main {
    display: grid; grid-template-columns: 2fr 1fr 1fr;
    gap: 48px; margin-bottom: 48px;
    padding-bottom: 48px; border-bottom: 1px solid rgba(255,255,255,0.07);
  }
  .footer-brand-name { font-size: 18px; font-weight: 700; color: #fff; margin-bottom: 6px; }
  .footer-brand-sub { font-size: 12px; color: rgba(255,255,255,0.35); margin-bottom: 18px; }
  .footer-tagline { font-size: 14px; color: rgba(255,255,255,0.55); line-height: 1.8; }
  .footer-heading { font-size: 12px; font-weight: 700; letter-spacing: .08em; text-transform: uppercase; color: rgba(255,255,255,0.3); margin-bottom: 18px; }
  .footer-links { list-style: none; display: flex; flex-direction: column; gap: 12px; }
  .footer-links a {
    font-size: 13.5px; color: rgba(255,255,255,0.5); text-decoration: none;
    transition: color var(--transition);
  }
  .footer-links a:hover { color: #fff; }
  .footer-bottom { display: flex; justify-content: space-between; align-items: center; gap: 16px; flex-wrap: wrap; }
  .footer-copy { font-size: 12px; color: rgba(255,255,255,0.2); }
  .footer-motto { font-size: 12.5px; font-weight: 600; color: rgba(201,106,58,0.7); }

  /* ── REVEAL ANIMATION ── */
  .reveal { opacity: 0; transform: translateY(24px); transition: opacity 0.6s ease, transform 0.6s ease; }
  .reveal.visible { opacity: 1; transform: none; }

  /* ── RESPONSIVE ── */
  @media (max-width: 900px) {
    .header-inner { padding: 0 20px; }
    .nav-links, .btn-contact { display: none; }
    .hamburger { display: flex; align-items: center; }
    .mobile-nav { display: none; }
    .mobile-nav.open { display: flex; }

    .hero { grid-template-columns: 1fr; gap: 40px; padding: 56px 20px 60px; }
    .hero-visual { justify-content: center; }
    .hero-illus { max-width: 100%; }

    .section { padding: 56px 20px; }
    .brand-grid { grid-template-columns: 1fr; gap: 36px; }
    .mission-stats { grid-template-columns: repeat(2,1fr); }
    .flow-steps { grid-template-columns: 1fr; gap: 24px; }
    .flow-step::after { display: none; }
    .ticket-grid { grid-template-columns: repeat(2,1fr); }
    .shelter-grid { grid-template-columns: 1fr; }
    .report-grid { grid-template-columns: 1fr; }
    .why-grid { grid-template-columns: 1fr; gap: 16px; }
    .wechat-box { grid-template-columns: 1fr; padding: 32px; gap: 28px; }
    .qr-placeholder { width: 100px; height: 100px; }
    .enterprise-grid { grid-template-columns: 1fr; }
    .enterprise-inner { padding: 56px 20px; }
    .footer-main { grid-template-columns: 1fr; gap: 32px; }
  }
  @media (max-width: 600px) {
    .ticket-grid { grid-template-columns: 1fr; }
    .mission-stats { grid-template-columns: repeat(2,1fr); }
    .hero-trust { gap: 12px; }
    .hero-actions { gap: 10px; }
    .btn-primary, .btn-ghost { font-size: 13.5px; padding: 12px 22px; }
  }
`;

